import styleInputText from "./Registration.module.css";
import React from "react";

const InputText = (props) => {
  return (
    <div>
      <div className={styleInputText.elem__container}>
        <label className={styleInputText.label} htmlFor="nickName">
          Nickname
        </label>
        <input placeholder="Например: Explore23" id="nickName" type="text" />
      </div>
    </div>
  );
};

export default InputText;
